// Application Insights: track availability test results across regions
availabilityResults
| where timestamp > ago(24h)
| summarize
    TotalTests = count(),
    Passed = countif(success == 1),
    Failed = countif(success == 0),
    AvailabilityPct = round(100.0 * countif(success == 1) / count(), 3)
  by location, name
| order by AvailabilityPct asc
// Azure creates synthetic transaction tests from global PoPs;
// failures here surface availability issues before users notice them
